namespace Skojjt.Core.Exports.Validation;
/// <summary>/// Pre-configured <see cref="AktivitetsbidragSettings"/> for known municipalities and years./// Add new entries here when rates change  no validator code changes needed./// </summary>public static class AktivitetsbidragKnownSettings{    /// <summary>    /// Göteborgs kommun 2026.    /// Flickor/kvinnor: 9,89 kr per deltagare och sammankomst.    /// Pojkar/män: 8,02 kr per deltagare och sammankomst.    /// </summary>    public static AktivitetsbidragSettings Goteborg2026 => new()    {        Namn = "Göteborgs kommun 2026",        KommunId = "1480",        Ar = 2026,        BeloppPerFlicka = 9.89m,        BeloppPerPojke = 8.02m,        MinAlderDeltagare = 7,        MaxAlderDeltagare = 25,        MinAlderLedare = 13,        MinAntalDeltagare = 3,        MinAntalLedare = 1,        MinSammankomstMinuter = 60,    };    /// <summary>    /// All known settings, most recent first.    /// </summary>    public static IReadOnlyList<AktivitetsbidragSettings> All => [Goteborg2026];    /// <summary>    /// Find the best matching settings for a given municipality and year.    /// Returns null if no match is found.    /// </summary>    public static AktivitetsbidragSettings? FindSettings(string? kommunId, int? year = null)    {        var candidates = All.AsEnumerable();        if (!string.IsNullOrWhiteSpace(kommunId))            candidates = candidates.Where(s => s.KommunId == null || s.KommunId == kommunId);        if (year.HasValue)            candidates = candidates.Where(s => s.Ar == null || s.Ar == year.Value);        return candidates.FirstOrDefault();    }}